// DFCT0010758 - "Awaiting Assignment" email is NOT sent to "Task Manager" or "Task Admin" when task is created in "Unassigned" state
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	//STRY0033443 Update Notification - Task Awaiting Assignment (N-14)
	if((current.isNewRecord() && current.state == -5) || 
		current.state.changesTo(-5) ||
		current.state==-5 && current.primary_assignee.changes()){
		var recipients='';
		var assigned_to = current.getValue('assigned_to') + '';
		var primary_assignee = current.getValue('primary_assignee') + '';
		var task_owner = current.getValue('u_task_requester') + '';
		var currentUser  = gs.getUserID();
		if ((current.operation() == 'update') || (current.operation() == 'insert')){
			if(primary_assignee != undefined && primary_assignee != ''){
				var OUTaskingAuthorities = current.primary_assignee.tasking_authorities;
				if(OUTaskingAuthorities!= undefined && OUTaskingAuthorities != ''){
					recipients += OUTaskingAuthorities;
				}else{
					var GlobalTaskingAuthorities = current.primary_office.u_global_authorities;
					recipients += GlobalTaskingAuthorities;
				}
			}
			gs.eventQueue("x_153465_discovert.NotificationAwaitingA",current,recipients,'empty');
		}
	}
})(current, previous);
